package assetresolver

import (
	"context"

	"google.golang.org/grpc"

	"github.snooguts.net/reddit/reddit-devplatform-monorepo/go-common/generated/protos/types/devvit/plugin/assetresolver"
	"github.snooguts.net/reddit/reddit-devplatform-monorepo/go-common/grpc/proxyutil"
)

type AssetResolverProxy struct {
	assetresolver.UnimplementedAssetResolverServer
	client assetresolver.AssetResolverClient
}

func init() {
	proxyutil.Register(&assetresolver.AssetResolver_ServiceDesc, NewAssetResolverProxy)
}
func NewAssetResolverProxy(cc grpc.ClientConnInterface) assetresolver.AssetResolverServer {
	return &AssetResolverProxy{client: assetresolver.NewAssetResolverClient(cc)}
}
func (p *AssetResolverProxy) GetAssetURL(ctx context.Context, in *assetresolver.GetAssetURLRequest) (*assetresolver.GetAssetURLResponse, error) {
	return proxyutil.ProxyMethod[assetresolver.GetAssetURLRequest, assetresolver.GetAssetURLResponse](p.client.GetAssetURL)(ctx, in)
}
func (p *AssetResolverProxy) GetAssetURLs(ctx context.Context, in *assetresolver.GetMultipleAssetURLsRequest) (*assetresolver.GetMultipleAssetURLsResponse, error) {
	return proxyutil.ProxyMethod[assetresolver.GetMultipleAssetURLsRequest, assetresolver.GetMultipleAssetURLsResponse](p.client.GetAssetURLs)(ctx, in)
}
